def somme(n):
    total = 0
    for i in range(1, n+1):
        total += i
    return total

def countdown(n):
    while n > 0:
        print(n)
        n -= 1
    print('Décollage !')

def division_securisee(a, b):
    try:
        return a / b
    except ZeroDivisionError:
        return 'Erreur: division par zéro'
